const safeItems = (nodeName) => {
  try {
    return $items(nodeName) || [];
  } catch (e) {
    return [];
  }
};

const oms = safeItems('Query OMS')[0]?.json ?? {};
const paymentTxnItems = safeItems('Query Payment - Txn');
const refundsItems = safeItems('Query Payment - Refunds');
const logisticsItems = safeItems('Query Logistics');
const inventoryItems = safeItems('Query Inventory');

const transaction = paymentTxnItems[0]?.json?.transaction ?? null;
const refund_records = refundsItems[0]?.json?.refund_records ?? null;
const shipment = logisticsItems[0]?.json?.shipment ?? null;
const tracking_events = logisticsItems[0]?.json?.tracking_events ?? null;
const stock_records = inventoryItems[0]?.json?.stock_records ?? null;

const input = $node['Webhook Trigger'].json.body || $json.body || $json;

const bundle = {
  order: oms.order ?? null,
  order_items: oms.order_items ?? [],
  transaction,
  refund_records,
  shipment,
  tracking_events,
  stock_records,
  dispute_type: input.dispute_type ?? null,
  queried_at: new Date().toISOString(),
};

return [{
  case_id: input.case_id,
  dispute_type: input.dispute_type,
  information_bundle: bundle,
}];

const caseData = $items('Fetch Full Case')[0]?.json ?? {};
const policies = $items('Fetch Policies')[0]?.json ?? [];

const dispute_type =
  caseData.dispute_type || $node['Webhook Trigger'].json.body.dispute_type;

const bundle = caseData.information_bundle ?? {};
const order = bundle.order ?? null;
const transaction = bundle.transaction ?? null;
const refundRecords = Array.isArray(bundle.refund_records) ? bundle.refund_records : [];
const shipment = bundle.shipment ?? null;
const trackingEvents = Array.isArray(bundle.tracking_events) ? bundle.tracking_events : [];
const stockRecords = Array.isArray(bundle.stock_records) ? bundle.stock_records : [];

const current_date = new Date().toISOString().split('T')[0];

const toDateOnly = (value) => {
  if (!value || typeof value !== 'string') return null;
  return value.includes('T') ? value.split('T')[0] : value;
};

const diffDaysUtc = (fromDate, toDate) => {
  if (!fromDate || !toDate) return null;
  const from = new Date(`${fromDate}T00:00:00Z`);
  const to = new Date(`${toDate}T00:00:00Z`);
  if (Number.isNaN(from.getTime()) || Number.isNaN(to.getTime())) return null;
  return Math.floor((to.getTime() - from.getTime()) / 86400000);
};

const order_created_date = toDateOnly(order?.created_at);
const days_since_order =
  order_created_date != null ? diffDaysUtc(order_created_date, current_date) : null;

const transaction_amount =
  transaction?.amount != null && !Number.isNaN(Number(transaction.amount))
    ? Number(transaction.amount)
    : null;

const refundFacts = {
  payment_status: transaction?.status ?? null,
  order_status: order?.status ?? null,
  transaction_amount,
  amount_threshold: 500,
  refund_record_count: refundRecords.length,
  order_created_date,
  days_since_order,
  within_return_window:
    days_since_order != null ? days_since_order >= 0 && days_since_order <= 30 : null,
};

const deliveryFacts = {
  shipment_status: shipment?.status ?? null,
  shipped_at: shipment?.shipped_at ?? null,
  estimated_delivery: shipment?.estimated_delivery ?? null,
  tracking_event_count: trackingEvents.length,
  stock_record_count: stockRecords.length,
  current_date,
};

const refundRules = [
  'Payment confirmed: sim_transactions.status = \'confirmed\'',
  'Order fulfilled or returned: sim_orders.status IN (\'fulfilled\',\'returned\')',
  'Amount below threshold: sim_transactions.amount <= 500 THB',
  'No prior dispute: sim_refund_records empty for this order_id',
  'Within return window: order created_at within 30 days of today',
];

const deliveryRules = [
  'Delay (not lost): sim_shipments.status = \'delayed\' NOT \'lost\'/\'failed\'',
  'Item shipped: sim_shipments.shipped_at IS NOT NULL',
  'No duplicate complaint: No prior open case for same order_id',
  'Within SLA window: sim_shipments.estimated_delivery >= today',
];

const triage_rules = dispute_type === 'refund' ? refundRules : deliveryRules;

const user_message = {
  information_bundle: bundle || null,
  dispute_type,
  triage_rules,
  policy_context: policies,
  current_date,
  facts: dispute_type === 'refund' ? { refund: refundFacts } : { delivery: deliveryFacts },
};

return [
  {
    case_id: caseData.id || $node['Webhook Trigger'].json.body.case_id,
    user_message,
  },
];

const coerceToString = (v) => {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') {
    if (typeof v.text === 'string') return v.text;
    if (typeof v.output === 'string') return v.output;
    if (typeof v.response === 'string') return v.response;
    if (v.response && typeof v.response.text === 'string') return v.response.text;
  }
  return String(v);
};

const promptItem = $items('Build Triage Prompt')[0]?.json ?? {};
const prompt = promptItem.user_message ?? {};
const disputeType = prompt.dispute_type;
const caseId =
  promptItem.case_id || $node['Webhook Trigger'].json.body.case_id;

let raw = $json;
let decision;

try {
  if (raw && typeof raw === 'object' && raw.routing_decision) {
    decision = raw;
  } else {
    const text = coerceToString(raw);
    decision = typeof text === 'string' && text.trim().length ? JSON.parse(text) : null;
  }
} catch (e) {
  decision = null;
}

const normalizeStringArray = (value) =>
  Array.isArray(value) ? value.filter((item) => typeof item === 'string') : [];

if (disputeType === 'refund') {
  const facts = prompt.facts?.refund ?? {};

  const amount = facts.transaction_amount;
  const daysSinceOrder = facts.days_since_order;

  const rules_evaluated = [
    {
      rule: "Payment confirmed: sim_transactions.status = 'confirmed'",
      passed: facts.payment_status === 'confirmed',
      evidence:
        facts.payment_status != null
          ? `Transaction status is '${facts.payment_status}'.`
          : 'Transaction status is missing.',
    },
    {
      rule: "Order fulfilled or returned: sim_orders.status IN ('fulfilled','returned')",
      passed: ['fulfilled', 'returned'].includes(facts.order_status),
      evidence:
        facts.order_status != null
          ? `Order status is '${facts.order_status}'.`
          : 'Order status is missing.',
    },
    {
      rule: 'Amount below threshold: sim_transactions.amount <= 500 THB',
      passed: typeof amount === 'number' && amount <= 500,
      evidence:
        typeof amount === 'number'
          ? `Transaction amount is ${amount} THB and threshold is 500 THB.`
          : 'Transaction amount is missing.',
    },
    {
      rule: 'No prior dispute: sim_refund_records empty for this order_id',
      passed: typeof facts.refund_record_count === 'number' && facts.refund_record_count === 0,
      evidence:
        typeof facts.refund_record_count === 'number'
          ? `refund_records contains ${facts.refund_record_count} record(s).`
          : 'refund_records data is missing.',
    },
    {
      rule: 'Within return window: order created_at within 30 days of today',
      passed:
        typeof daysSinceOrder === 'number' &&
        daysSinceOrder >= 0 &&
        daysSinceOrder <= 30,
      evidence:
        facts.order_created_date != null && typeof daysSinceOrder === 'number'
          ? `Order created_at is ${facts.order_created_date} and is ${daysSinceOrder} day(s) old.`
          : 'Order created_at is missing.',
    },
  ];

  const routing_decision = rules_evaluated.every((rule) => rule.passed)
    ? 'autonomous'
    : 'escalation';

  const failedRules = rules_evaluated
    .filter((rule) => !rule.passed)
    .map((rule) => rule.rule);

  const justification =
    routing_decision === 'autonomous'
      ? `All refund triage rules passed based on the information bundle. Transaction amount ${amount} THB is within the 500 THB threshold and the order is within the 30-day return window.`
      : `Refund triage requires escalation because the following rule(s) failed: ${failedRules.join('; ')}.`;

  return [
    {
      case_id: caseId,
      routing_decision,
      rules_evaluated,
      justification,
      policies_applied: normalizeStringArray(decision?.policies_applied),
      slas_applied: normalizeStringArray(decision?.slas_applied),
    },
  ];
}

const ok =
  decision &&
  (decision.routing_decision === 'autonomous' ||
    decision.routing_decision === 'escalation');

const safeDecision = ok
  ? {
      routing_decision: decision.routing_decision,
      rules_evaluated: Array.isArray(decision.rules_evaluated) ? decision.rules_evaluated : [],
      justification:
        typeof decision.justification === 'string' && decision.justification.trim().length
          ? decision.justification
          : 'Triage completed.',
      policies_applied: normalizeStringArray(decision.policies_applied),
      slas_applied: normalizeStringArray(decision.slas_applied),
    }
  : {
      routing_decision: 'escalation',
      rules_evaluated: [],
      justification: 'Triage error - manual review required.',
      policies_applied: [],
      slas_applied: [],
    };

return [
  {
    case_id: caseId,
    ...safeDecision,
  },
];

const c = $items('Fetch Full Case')[0]?.json ?? {};

const user_message = {
  dispute_type: c.dispute_type ?? null,
  order_id: c.order_id ?? null,
  customer_name: c.customer_name ?? null,
  information_bundle: c.information_bundle ?? null,
  triage_decision: c.triage_decision ?? null,
};

return [{
  case_id: c.id || $node['Webhook Trigger'].json.body.case_id,
  user_message,
}];

const caseData = $items('Fetch Full Case')[0]?.json ?? {};

const coerceToString = (v) => {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'object') {
    if (typeof v.text === 'string') return v.text;
    if (typeof v.output === 'string') return v.output;
    if (typeof v.response === 'string') return v.response;
    if (v.response && typeof v.response.text === 'string') return v.response.text;
  }
  return String(v);
};

let summary;
try {
  if ($json && typeof $json === 'object' && ($json.summary || $json.key_facts)) {
    summary = $json;
  } else {
    const text = coerceToString($json);
    summary = JSON.parse(text);
  }
} catch (e) {
  summary = null;
}

const valid = summary
  && typeof summary.summary === 'string'
  && Array.isArray(summary.key_facts)
  && typeof summary.escalation_reason === 'string'
  && typeof summary.recommended_action === 'string'
  && Array.isArray(summary.data_sources_queried)
  && Array.isArray(summary.policies_relevant);

if (!valid) {
  summary = {
    summary: `Escalated ${caseData.dispute_type || 'unknown'} dispute for order ${caseData.order_id || 'unknown'}.`,
    key_facts: [
      caseData.triage_decision?.justification || 'Escalation due to triage error or incomplete data.',
    ],
    escalation_reason: 'LLM summarization failed, using minimal fallback.',
    recommended_action: 'Human agent should review the full case bundle and triage decision.',
    data_sources_queried: ['oms'],
    policies_relevant: [],
  };
}

return [{
  case_id: caseData.id || $node['Webhook Trigger'].json.body.case_id,
  summary,
}];

