if (plan.resolution_type === 'refund' && typeof plan.amount !== 'number') {
  plan.amount = 0;
}

return [{
  case_id: $items('Build Plan Prompt')[0]?.json.case_id || $node['Webhook - Plan'].json.body.case_id,
  ...plan,
}];

